/**
 * Arc-wrapped 29er native runtime + NIP-29 verbs.
 */
public protocol TwentyNinerAppProtocol: AnyObject, Sendable {
    
    /**
     * Add a relay. `role` is an NMP relay-role token (e.g. `"both"`).
     */
    func addRelay(url: String, role: String) 
    
    /**
     * Close the current NIP-29 group-discovery session (if any).
     */
    func closeGroupDiscovery() 
    
    /**
     * Reconfigure rendering limits without restarting (same clamps as `start`).
     */
    func configure(visibleLimit: UInt32, emitHz: UInt32) 
    
    /**
     * Declare that 29er consumes every kernel-owned built-in Tier-2 projection
     * (full client). Pre-start; idempotent.
     */
    func declareConsumedProjections() 
    
    /**
     * ADR-0055 Rung 3 — declare that 29er's runtime owns the NMP cache-merge
     * layer (D3-3) so the kernel may omit `Unchanged` projections from the
     * frame. Single-writer; call before [`Self::start`]. `true` on success
     * (or idempotent re-call); `false` if called after start / the registry is
     * unavailable (informational — the kernel then emits full rows).
     */
    func declareIncrementalApply()  -> Bool
    
    /**
     * Dispatch a pre-built `DispatchEnvelope` (the generic byte lane, ADR-0071).
     */
    func dispatchAction(envelope: Data)  -> DispatchOutcome
    
    /**
     * Dispatch a NIP-29 action by `(namespace, body_json)`. 29er builds the
     * typed payload + envelope in Rust so the shell hand-assembles no
     * FlatBuffers. The `nmp.nip29.post_chat_message` doorway runs the shared
     * composer and re-emits under `nmp.nip29.publish_group_event`. D6
     * fail-closed: an unknown namespace / malformed body surfaces as
     * `DispatchOutcome.error`.
     */
    func dispatchNip29Action(namespace: String, bodyJson: String)  -> DispatchOutcome
    
    /**
     * Actor-liveness probe (ADR-0028). `true` while the actor thread runs.
     */
    func isAlive()  -> Bool
    
    /**
     * Report iOS scenePhase = `.background`. Fire-and-forget.
     */
    func lifecycleBackground() 
    
    /**
     * Report iOS scenePhase = `.active`. Fire-and-forget.
     */
    func lifecycleForeground() 
    
    /**
     * Mark a group's direct kind:9 messages read inside the open group-tree
     * session. The next tree snapshot folds the read state into unread counts.
     */
    func markGroupRead(groupId: String) 
    
    /**
     * Open a NIP-29 group-discovery session for one host relay (singleton).
     * Closes any prior session first. `true` on success.
     */
    func openGroupDiscovery(hostRelayUrl: String)  -> Bool
    
    /**
     * Refresh group discovery after a local store reset: tear down the current
     * session, open a fresh one for `host_relay_url`, and re-dispatch
     * `nmp.nip29.discover`. `true` when the new session opened.
     */
    func refreshGroupDiscovery(hostRelayUrl: String)  -> Bool
    
    /**
     * Wire a single NIP-29 group's chat-message read view (kinds 9 + 11).
     * Singleton: re-opening replaces the prior group-events view.
     */
    func registerGroupChat(groupIdJson: String) 
    
    /**
     * Add a relay to the user's NIP-51 relay set + select it.
     */
    func relaySelectorAddRelay(relayUrl: String)  -> Bool
    
    /**
     * Remove a relay from the user's NIP-51 relay set.
     */
    func relaySelectorRemoveRelay(relayUrl: String)  -> Bool
    
    /**
     * Select the active NIP-29 relay. `true` when a known relay was selected.
     */
    func relaySelectorSelectRelay(relayUrl: String)  -> Bool
    
    /**
     * Release an event ref acquired through a typed event adapter. Idempotent.
     */
    func releaseEventRef(key: String, consumerId: String) 
    
    /**
     * Release a profile ref acquired through a typed profile adapter.
     * Idempotent (D6).
     */
    func releaseProfileRef(key: String, consumerId: String) 
    
    /**
     * Remove an identity; the actor owns the active-account transition.
     */
    func removeAccount(identityId: String) 
    
    /**
     * Reset transient kernel state.
     */
    func reset() 
    
    /**
     * Resolve an event embed (embed shape, CacheOk liveness). Use for embedded
     * `nostr:nevent`/`naddr` cards in rendered content. D6 / fire-and-forget.
     */
    func resolveEventEmbed(key: String, consumerId: String) 
    
    /**
     * Resolve a live event embed (tailing subscription).
     */
    func resolveEventEmbedLive(key: String, consumerId: String) 
    
    /**
     * Resolve a live profile card (full-card shape, Live liveness). Use for
     * open profile screens. D6: invalid `key` is a silent no-op.
     */
    func resolveProfileCardLive(key: String, consumerId: String) 
    
    /**
     * Resolve a profile ref (feed-avatar shape, CacheOk liveness). Use for
     * feed-row avatars. D6: invalid `key` is a silent no-op; fire-and-forget.
     */
    func resolveProfileRef(key: String, consumerId: String) 
    
    /**
     * Retry a parked publish-outbox row by its handle.
