     * `nmp-uniffi::NmpApp::set_update_sink`.
     */
    func setUpdateSink(sink: UpdateSink?) 
    
    /**
     * Idempotent teardown: clears the sink, sends Shutdown, joins threads.
     */
    func shutdown() 
    
    /**
     * Sign in with a local nsec and (when `make_active`) activate it. The nsec
