/**
 * Typed outcome of a dispatch. Exactly one of `correlation_id` (accepted) or
 * `error` (rejected/failed) is `Some`; `code` is present only for coded
 * rejections (issue #1734). Mirrors `nmp-uniffi::DispatchOutcome`.
 */
public struct DispatchOutcome {
    public var correlationId: String?
    public var error: String?
    public var code: String?

    // Default memberwise initializers are never public by default, so we
    // declare one manually.
    public init(correlationId: String?, error: String?, code: String?) {
        self.correlationId = correlationId
        self.error = error
        self.code = code
    }
}

#if compiler(>=6)
extension DispatchOutcome: Sendable {}
#endif


extension DispatchOutcome: Equatable, Hashable {
    public static func ==(lhs: DispatchOutcome, rhs: DispatchOutcome) -> Bool {
        if lhs.correlationId != rhs.correlationId {
            return false
        }
        if lhs.error != rhs.error {
            return false
        }
        if lhs.code != rhs.code {
            return false
        }
        return true
    }

    public func hash(into hasher: inout Hasher) {
        hasher.combine(correlationId)
        hasher.combine(error)
        hasher.combine(code)
    }
}



